class Solution:
    def isZeroArray(self, nums, queries):
        n = len(nums)
        cov = [0] * n
        for l, r in queries:
            for i in range(l, r + 1):
                cov[i] += 1
        return all(cov[i] >= nums[i] for i in range(n))

