class Solution:
    def isZeroArray(self, nums, queries):
        n = len(nums)
        diff = [0] * (n + 1)
        for l, r in queries:
            diff[l] += 1
            diff[r + 1] -= 1
        cov = 0
        for i in range(n):
            cov += diff[i]
            if cov < nums[i]:
                return False
        return True

